import axios from 'axios';

async function send(method,url,formdata){
    let resp;
    if(method == 'post'){
        resp = await axios.post(url,formdata);
    }else if(method == 'get'){
        resp = await axios.get(url);
    }
    return resp;
}

function validateForm(obj,rules){
    let validated = {
        allValid: true
    };

    for(let r in rules){
        if((rules[r] == "required" || rules[r].isRequired ) &&
            obj[r] == undefined || obj[r] == '' ){
                validated[r] = 'empty';  1
        }else if((rules[r] != "required" || rules[r].isRequired ) &&
            obj[r] == undefined || obj[r] == '' ){
                validated[r] = true;  
        }else{
            let emailregex = /[a-z0-9]+@[a-z]+\.[a-z]{2,3}/;
            let intregex = /[0-9]+/;

            validated[r] = true;

            if(rules[r].isEmail == true &&  obj[r].toLowerCase().match(emailregex))
                validated[r] = true;
            else if (rules[r].isEmail == true )
                validated[r] = 'invalid email';

            if(rules[r].isInteger == true && obj[r].match(intregex))
                validated[r] = true;
            else if(rules[r].isInteger == true) 
                validated[r] = 'invalid number';
        }
    }

    for(let v in validated){
        if(validated[v] != true){
            validated.allValid = false;
            break;
        }
    }

    return validated;
}

function toFormData(obj){
    var fd = new FormData();
    for(var i in obj){
        fd.append(i,obj[i]);
    }
    return fd;
}

export { toFormData, send, validateForm };