<template>
    <ion-page>
        <div class="login">
            <ion-img src="assets/icon/main-logo.png"></ion-img>
            <h2>Congratulations</h2>
            <p>Your account has been approved</p>
        </div>
        <ion-fab vertical="bottom" horizontal="center">
          <ion-fab-button @click="congrats">
            <ion-icon :icon="chevronForwardOutline"></ion-icon>
          </ion-fab-button>
        </ion-fab>
    </ion-page>
</template>

<script>
import { IonPage, IonImg, IonFabButton } from '@ionic/vue';
import { chevronForwardOutline } from 'ionicons/icons';
import { toFormData, send } from '../functions.js';

export default {
    name: 'HomePage',
    components: {
        IonPage,
        IonImg,
        IonFabButton
    },
    setup() {
      return { chevronForwardOutline };
    },
    beforeMount() {
        console.log(localStorage.getItem('currentUser'));
        this.currentUserId = JSON.parse(localStorage.getItem('currentUser'));
    },
    methods: {
        async congrats() {
            let formdata = toFormData({
                form: 'congrats',
                action: 'status_change',
                match: 'customer_id',
                customer_id: this.currentUserId
            });
            send('post','http://ns.proweaver.host/super_archive/james/api/api.php',formdata)
                .then(response=>{
                    console.log(response);
                    this.$router.push('/main');
            });
        }
    }
}
</script>

<style scoped>
.ion-page {
	background: #000;
}

ion-img {
    width: 200px;
    margin: 0 auto 20px;
}

.login {
    display: flex;
    flex-flow: column wrap;
    justify-content: center;
    align-items: center;
    text-align: center;
}

.login h2 {
    font-size: 22px;
    color: #232323;
    margin-bottom: 0;
}

.login p {
    font-size: 14px;
    font-weight: 300;
    color: #828282;
}

ion-icon {
    --color: #fff;
    --background: #fff;
}
</style>