<template>
    <ion-page>
        <div class="login">
            <ion-img src="assets/icon/main-logo.png"></ion-img>

            <form action="#" @submit.prevent="submit">
                <ion-input placeholder="Username" type="text" v-model="user.username"></ion-input>
                <ion-input placeholder="Password" type="password" v-model="user.password"></ion-input>
                <ion-button v-bind:disabled="formRequest" expand="block" @click="login">
                    <span v-if="!formRequest">Login</span>
                    <span v-if="formRequest">
                        <ion-spinner name="dots"></ion-spinner>
                    </span>
                </ion-button>
                <ion-button router-link="/register" color="secondary" expand="block">
                    <span>Register</span>
                </ion-button>
                <ion-router-link href="#" color="secondary">Forgot Password</ion-router-link>
            </form>
        </div>
    </ion-page>
</template>

<script>
import { IonPage, IonInput, IonButton, IonImg, IonSpinner, toastController } from '@ionic/vue';
import { checkmarkCircle, warning } from 'ionicons/icons';
import { toFormData, send } from '../functions.js';

export default {
    name: 'LoginPage',
    components: {
        IonPage,
        IonButton,
        IonInput,
        IonImg,
        IonSpinner
    },
    data() {
        return {
            user: {},
            isSuccessful: '',
            formIsValid: true,
            formRequest: false,
            formResponse: null,
        }
    },
    methods: {
        async login() {
            this.formRequest = true;
            this.formResponse = '';

            let formdata = toFormData({
                form: 'login',
                action: 'read',
                match: 'username',
                username: this.user.username
            });
            
            if ( this.user.username === '' || this.user.password === '' || this.user.password.length < 6 ) {
                if ( this.user.username === '' || this.user.password === '' ) {
                    this.formResponse = "Username and password is required";
                } else if ( this.user.password.length < 6 ) {
                    this.formResponse = "Minimum password is 6 characters";
                }
                this.formRequest = false;
                this.openToast();
            } else {
                send('post','http://ns.proweaver.host/super_archive/james/api/api.php',formdata)
                .then(response=>{
                    console.log(response);
                    console.log(response.data[0].customer_id);
                    const currentUser = response.data[0].customer_id;
                    let formdata2 = toFormData({
                        form: 'hash_compare',
                        action: 'hash_check',
                        value: this.user.password,
                        hashedValue: response.data[0].password
                    });
                    send('post','http://ns.proweaver.host/super_archive/james/api/api.php',formdata2)
                    .then(response=>{
                        if(response.data == true){
                            console.log(response);
                            localStorage.setItem('currentUser', JSON.stringify(currentUser));
                            this.formResponse = "Login Success";
                            this.openToast();
                            this.formRequest = false;
                            let formdata3 = toFormData({
                                form: 'customer_status',
                                action: 'status_check',
                                username: this.user.username,
                            });
                            send('post','http://ns.proweaver.host/super_archive/james/api/api.php',formdata3)
                            .then(response=>{
                                if (response.data == "accepted") {
                                    console.log(response);
                                    this.$router.push('/congrats');
                                } else if (response.data == "proceed") {
                                    console.log(response);
                                    this.$router.push('/main');
                                } else {
                                    console.log(response);
                                    this.$router.push('/pending');
                                }
                            });
                        } else {
                            console.log(response);
                            this.formResponse = "Username or password is incorrect";
                            this.openToast();
                            this.formRequest = false;
                        }
                    });
                });
            }
        },
        async openToast() {
            try {
                await toastController.dismiss();
            } catch(e) {
                console.log(e);
            }

            if (this.formResponse === "Login Success") {
                this.color = 'success';
                this.icon = checkmarkCircle;
            } else {
                this.color = 'primary';
                this.icon = warning;
            }

            const toast = await toastController
                .create({
                    message: this.formResponse,
                    position: 'top',
                    color: this.color,
                    icon: this.icon,
                    cssClass: 'custom-toast',
                    duration: 3000
                })
            return toast.present();
        },
    },
};
</script>

<style scoped>
.ion-page {
    background: #f4f4f4;
}

ion-input {
  width: 100%;
  height: 50px;
  padding: 0 !important;
  --padding-start: 30px !important;
  --padding-end: 30px !important;
  margin-top: 15px;
  border: 1px solid #d8d8d8;
  border-radius: 5px;
  color: #515151;
}

ion-button {
    height: 55px;
    margin: 15px auto 0;
    --border-radius: 5px;
}

ion-router-link {
    font-size: 16px;
    position: relative;
    display: block;
    margin: 15px auto 0;
    color: #464646; 
    text-align: center;
}

.ion-page::after {
    content: '';
    position: absolute;
    width: 100vw;
    height: 50vh;
    background: #000;
    z-index: -1;
    bottom: 0;
}

ion-img {
    width: 200px;
    margin: 0 auto;
}
</style>
