<template>
    <ion-text>
        <h2>RideShare</h2>
    </ion-text>
    <ion-card>
        <div id="map"></div>
        <ion-card class="map-form">
            <ion-card-header class="close">
                <span><ion-icon :icon="close"></ion-icon></span>
            </ion-card-header>
            <div id="geocoder" class="input-con" :class="{ 'focused': focused }" @focus="focused = true" @blur="focused = false">
                <div id="geocoder1">
                    <ion-icon id="currentlocation" :icon="compass"></ion-icon>
                </div>
                <div id="geocoder2">
                    <ion-icon id="currentlocation" :icon="navigateCircle"></ion-icon>
                </div>
            </div>
        </ion-card>
    </ion-card>
</template>

<script>
import axios from 'axios';
import { IonCard, toastController } from '@ionic/vue';
import { locate, compass, navigateCircle, warning, close } from 'ionicons/icons';
import mapboxgl from 'mapbox-gl';
import MapboxGeocoder from '@mapbox/mapbox-gl-geocoder';
import '@mapbox/mapbox-gl-geocoder/dist/mapbox-gl-geocoder.css';

// Website address 
// https://account.mapbox.com
// username: speedyrepair
// password: TGP9!J9n^MYm#Tx

// username: dev
// password: F77GBCmu2cvL8RF

export default {
    name: "MapBox",
    components: {
        IonCard
    },
    directives: {
        // enables v-focus in template
        focus
    },
    data() {
        return {
            formResponse: null,
            address: '',
            focused: false
        }
    },
    methods: {
        async openToast() {
            try {
                await toastController.dismiss();
            } catch(e) {
                console.log(e);
            }

            if (this.formResponse === "User denied geolocation prompt") {
                this.color = 'primary';
                this.icon = warning;
            }

            const toast = await toastController
                .create({
                    message: this.formResponse,
                    position: 'top',
                    color: this.color,
                    icon: this.icon,
                    cssClass: 'custom-toast',
                    duration: 3000
                })
            return toast.present();
        },
    },
    mounted() {

        mapboxgl.accessToken = 'pk.eyJ1Ijoic3BlZWR5cmVwYWlyIiwiYSI6ImNsNWg4cGlzaDA3NTYzZHFxdm1iMTJ2cWQifQ.j_XBhRHLg-CcGzah7uepMA';

        const getLocation = () => new Promise(
            (resolve, reject) => {
                window.navigator.geolocation.getCurrentPosition(
                    position => {
                        const location = {
                            lat:position.coords.latitude,
                            long:position.coords.longitude
                        };
                        resolve(location); // Resolve with location. location can now be accessed in the .then method.
                    },
                    err => {
                        this.formResponse = `${err.message}`;
                        this.openToast();
                        reject(err) // Reject with err. err can now be accessed in the .catch method.
                    }
                );
            }
        );

        getLocation().then(location => { // Initiate getLocation function
            const map = new mapboxgl.Map({
                container: 'map',
                style: 'mapbox://styles/speedyrepair/cl5h8u6it000116omwkioew0k',
                center: [location.long, location.lat],
                // center: [-122.662323, 45.523751],
                zoom: 12
            });

            // Initialize the geolocate control.
            const locate = new mapboxgl.GeolocateControl({
                geolocation: window.navigator.geolocation,
                positionOptions: {
                    enableHighAccuracy: true
                },
                showUserHeading: true,
                showUserLocation: true,
                trackUserLocation: true
            });

            // Add the geolocate control to the map.
            map.addControl(locate);

            axios.get(`https://api.mapbox.com/geocoding/v5/mapbox.places/${location.long},${location.lat}.json?access_token=pk.eyJ1Ijoic3BlZWR5cmVwYWlyIiwiYSI6ImNsNWg4cGlzaDA3NTYzZHFxdm1iMTJ2cWQifQ.j_XBhRHLg-CcGzah7uepMA`)
                .then(({data}) => {
                    console.log(data);
                    console.log(data.features[5].place_name);
                    var userCountry = data.features[5].properties.short_code;
                    var userOutbound = data.features[5].bbox;
                    console.log(userCountry);
                    console.log(userOutbound);

                    // Initialize the geocoder controls.
                    const geocoder1 = new MapboxGeocoder({
                        accessToken: mapboxgl.accessToken,
                        placeholder: 'Pick Up Address',
                        countries: userCountry,
                        bbox: userOutbound,
                        limit: 10,
                        mapboxgl: mapboxgl
                    });

                    const geocoder2 = new MapboxGeocoder({
                        accessToken: mapboxgl.accessToken,
                        placeholder: 'Drop Off Address',
                        countries: userCountry,
                        bbox: userOutbound,
                        limit: 10,
                        mapboxgl: mapboxgl
                    });

                    // Add the geocoder controls to the map.
                    geocoder1.addTo('#geocoder1');
                    geocoder2.addTo('#geocoder2');

                    let input1 = document.querySelectorAll('#geocoder input');

                    input1.forEach(i => {
                        i.addEventListener('click', function() {
                            document.querySelector(".map-form").classList.add('active');
                        });
                    });

                    let input2 = document.querySelectorAll('.close');

                    input2.forEach(i => {
                        i.addEventListener('click', function() {
                            document.querySelector(".map-form").classList.remove('active');
                        });
                    });
                    
                    // let coordinates;

                    // if (navigator.geolocation) {
                    //     navigator.geolocation.getCurrentPosition(function(position) {
                    //         coordinates = [position.coords.latitude, position.coords.longitude];
                    //         console.log(coordinates);

                    //         map.flyTo({
                    //             center: [
                    //                 position.coords.longitude,
                    //                 position.coords.latitude
                    //         ],
                    //             essential: true // this animation is considered essential with respect to prefers-reduced-motion
                    //         });

                    //     });
                    // } else {
                    //     map.flyTo({
                    //         center: [
                    //             -122.662323,
                    //             45.523751
                    //     ],
                    //         essential: true // this animation is considered essential with respect to prefers-reduced-motion
                    //     });
                    // }

                    document.getElementById('currentlocation').onclick = function(){
                        // locate.trigger();

                        var userAddress = data.features[0].place_name;

                        if (map.getSource('points') != null) {
                            map.flyTo({
                                center: [location.long, location.lat],
                                zoom: 15
                            });
                        } else {
                            map.flyTo({
                                center: [location.long, location.lat],
                                zoom: 15
                            });
                            map.addSource('points', {
                                'type': 'geojson',
                                'data': {
                                    'type': 'FeatureCollection',
                                    'features': [
                                        {
                                            'type': 'Feature',
                                            'properties': {},
                                            'geometry': {
                                                'type': 'Point',
                                                'coordinates': [location.long, location.lat]
                                            }
                                        }
                                    ]
                                }
                            });
                            map.addLayer({
                                'id': 'circle',
                                'type': 'circle',
                                'source': 'points',
                                'paint': {
                                    'circle-color': '#b7160b',
                                    'circle-radius': 8,
                                    'circle-stroke-width': 2,
                                    'circle-stroke-color': '#ffffff'
                                }
                            });
                        }

                        document.querySelector("#geocoder1 .mapboxgl-ctrl-geocoder--input").value = userAddress;

                    }

                    const start = [location.long, location.lat];

                    console.log(start);

                    map.on('click', (event) => {
                        const coords = Object.keys(event.lngLat).map((key) => event.lngLat[key]);
                        console.log(coords);
                        axios.get(`https://api.mapbox.com/geocoding/v5/mapbox.places/${coords}.json?access_token=pk.eyJ1Ijoic3BlZWR5cmVwYWlyIiwiYSI6ImNsNWg4cGlzaDA3NTYzZHFxdm1iMTJ2cWQifQ.j_XBhRHLg-CcGzah7uepMA`)
                            .then(({data}) => {
                                console.log(data);
                                console.log(data.features[0].place_name);
                                var userAddress = data.features[0].place_name;
                                document.querySelector("#geocoder2 .mapboxgl-ctrl-geocoder--input").value = userAddress;
                            });

                            const end = {
                                type: 'FeatureCollection',
                                features: [
                                {
                                    type: 'Feature',
                                    properties: {},
                                    geometry: {
                                    type: 'Point',
                                    coordinates: coords
                                    }
                                }
                                ]
                            };

                            if (map.getLayer('end')) {
                                map.getSource('end').setData(end);
                            } else {
                                map.addLayer({
                                id: 'end',
                                type: 'circle',
                                source: {
                                    type: 'geojson',
                                    data: {
                                    type: 'FeatureCollection',
                                    features: [
                                        {
                                        type: 'Feature',
                                        properties: {},
                                        geometry: {
                                            type: 'Point',
                                            coordinates: coords
                                        }
                                        }
                                    ]
                                    }
                                },
                                paint: {
                                    'circle-color': '#333',
                                    'circle-radius': 8,
                                    'circle-stroke-width': 2,
                                    'circle-stroke-color': '#ffffff'
                                }
                                });
                            }

                            getRoute(coords);
                    });

                    // create a function to make a directions request
                    async function getRoute(end) {
                        // make a directions request using driving profile
                        const query = await fetch(
                            `https://api.mapbox.com/directions/v5/mapbox/driving/${start[0]},${start[1]};${end[0]},${end[1]}?steps=true&geometries=geojson&access_token=${mapboxgl.accessToken}`,
                            { method: 'GET' }
                        );
                        const json = await query.json();
                        const data = json.routes[0];
                        const route = data.geometry.coordinates;
                        const geojson = {
                            type: 'Feature',
                            properties: {},
                            geometry: {
                                type: 'LineString',
                                coordinates: route
                            }
                        };
                        // if the route already exists on the map, we'll reset it using setData
                        if (map.getSource('route')) {
                            map.getSource('route').setData(geojson);
                        }
                        // otherwise, we'll make a new request
                        else {
                            map.addLayer({
                            id: 'route',
                            type: 'line',
                            source: {
                                type: 'geojson',
                                data: geojson
                            },
                            layout: {
                                'line-join': 'round',
                                'line-cap': 'round'
                            },
                            paint: {
                                'line-color': '#3887be',
                                'line-width': 5,
                                'line-opacity': 0.75
                            }
                            });
                        }
                        // add turn instructions here at the end
                    }

                    geocoder2.on('result', result => console.log(result));

                    map.on('style.load', () => {
                        map.resize();
                        getRoute(start);
                        // locate.trigger();
                    });

            });

        });
    },
    setup() {
        return { locate, compass, navigateCircle, warning, close };
    }
};
</script>

<style scoped>
#map {
    border: none;
    width: 100%;
    height: 100%;
    border-radius: 20px 20px 0 0;
}

ion-card {
    width: 100%;
    height: 100%;
    margin: auto;
    background: none;
    overflow: visible;
}

ion-text {
    display: block;
    text-align: center;
}

ion-text h2 {
    margin: 0 auto 15px;
}

.map-form {
	position: relative;
    bottom: 0;
    left: 0;
    right: 0;
    margin: auto;
}

.map-form {
	position: absolute;
    top: calc(100% - 126px);
    width: calc(100% - 30px);
    height: auto;
    padding: 0 !important;
    border-radius: 0;
    color: #515151;
    margin: auto;
    z-index: 11;
    transition: all 500ms ease-in-out;
}

.map-form.active {
    width: 100%;
	top: 0;
	bottom: 0;
	padding: 0 !important;
	background: #fff;
	border-radius: 20px 20px 0 0;
	overflow: hidden;
}

.close {
    display: none;
	justify-content: center;
	align-items: center;
}

.map-form.active .close {
    display: flex;
    width: 100%;
    justify-content: flex-end;
    padding: 15px 10px;
}

.map-form.active .close span ion-icon {
    position: static;
    transform: none;
}

.map-form.active #geocoder {
    width: 100%;
    margin: 0 auto;
}

#geocoder1 {
    position: relative;
    background-color: #fff;
    border-bottom: 1px solid rgb(235, 235, 235);
}

#geocoder2 {
    position: relative;
    background-color: #fff;
}

ion-icon {
    position: absolute;
    top: 50%;
    right: 10px;
    z-index: 12;
    width: 25px;
    height: 25px;
    margin: 0;
    transform: translateY(-50%);
}

ion-icon {
    --border-radius: 0;
    --background: none;
    /* --background: #b7160b; */
    --background-activated: none;
    --ripple-color: none;
    --box-shadow: none;
    color: #b7160b;
}

#geocoder2 ion-icon {
    color: #333;
}

#geocoder2 ion-icon:hover {
    cursor: unset;
}

ion-icon:hover {
    color: #791c18;
    cursor: pointer;
}

ion-icon:active {
    color: #333;
}

ion-input a {
	position: absolute;
	left: 15px;
	font-size: 20px;
	color: #b7160b;
}
</style>