import { createRouter, createWebHistory } from '@ionic/vue-router';
import CongratsPage from '../views/CongratsPage.vue'
import AfterSplash from '../views/AfterSplash.vue';
import LoginPage from '../views/LoginPage.vue';
import RegisterPage from '../views/RegisterPage.vue';
import PendingPage from '../views/PendingPage.vue';
import MainPage from '../views/MainPage.vue';

const routes = [
  {path: '/', redirect: '/after-splash'},
  {path: '/congrats', name: 'CongratsPage', component: CongratsPage},
  {path: '/after-splash', name: 'AfterSplashPage', component: AfterSplash},
  {path: '/login', name: 'LoginPage', component: LoginPage},
  {path: '/register', name: 'RegisterPage', component: RegisterPage},
  {path: '/pending', name: 'PendingPage', component: PendingPage},
  {path: '/main', name: 'MainPage', component: MainPage},
]

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes
});

export default router
export { routes }